def minimax(node, is_maximizing):
    if isinstance(node, int):       # leaf: return the score
        return node
    if is_maximizing:
        best = -999
        for child in node:
            val = minimax(child, False)
            if val > best:
                best = val
        return best
    else:
        best = 999
        for child in node:
            val = minimax(child, True)
            if val < best:
                best = val
        return best

tree = [[3, 5], [2, 9], [0, 7]]
# MIN picks 3 from [3,5], 2 from [2,9], 0 from [0,7]
# MAX then picks 3 from {3, 2, 0}
root_value = minimax(tree, True)
print("Root value:", root_value)       # 3

best_idx = None
best_val = -999
for i, child in enumerate(tree):
    val = minimax(child, False)
    if val > best_val:
        best_val = val
        best_idx = i
print("Best move index:", best_idx)    # 0
